#include <bits/stdc++.h>
using namespace std;
char s[1001]="0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
char ans[10001];
int main() {
	int x,m;
	cin>>x>>m;
	int i=0;
	while(x!=0) {
		int t=x%m;
		x=x/m;
		ans[i++]=s[t];
	}
	for(int j=i-1; j>=0; j--) {
		cout<<ans[j];
	}
	return 0;
}
